export enum ReportType {
  LIVE_COMMENT = '直播评论举报',
  LIVE_ROOM = '直播间举报',
  VOICE_CHAT_COMMENT = '语聊评论举报',
  VOICE_CHAT_USER = '语聊用户举报',
  TOPIC = '话题举报',
  FEED_COMMENT = '信息流评论举报',
  FEED_POST = '信息流帖子举报',
  REPORT_NEW = '举报NEW',
  SENSITIVE_WORD = '敏感词举报',
  GROUP_SENSITIVE_WORD = '群敏感词举报',
}

export enum ReportStatus {
  PENDING = 'PENDING',       // Waiting for review
  INVESTIGATING = 'INVESTIGATING', // Under review
  RESOLVED_PUNISHED = 'RESOLVED_PUNISHED', // Violation confirmed
  RESOLVED_NO_ACTION = 'RESOLVED_NO_ACTION', // Insufficient evidence
}

export interface User {
  id: string;
  name: string;
  avatar: string;
  reportCount: number; // To track the >5 auto-ban rule
}

export interface ReportEvent {
  status: ReportStatus;
  timestamp: number;
  description: string;
}

export interface Report {
  id: string;
  targetUser: User;
  type: ReportType;
  reason: string; // e.g., "Harassment", "Spam"
  status: ReportStatus;
  timeline: ReportEvent[];
  createdAt: number;
  updatedAt: number;
}

export const formatTime = (timestamp: number): string => {
  const date = new Date(timestamp);
  const now = new Date();

  const isToday = date.getDate() === now.getDate() && 
                  date.getMonth() === now.getMonth() && 
                  date.getFullYear() === now.getFullYear();

  const isYesterday = new Date(now.setDate(now.getDate() - 1)).getDate() === date.getDate();

  const hours = date.getHours().toString().padStart(2, '0');
  const minutes = date.getMinutes().toString().padStart(2, '0');

  if (isToday) {
    return `今天 ${hours}:${minutes}`;
  } else if (isYesterday) {
    return `昨天 ${hours}:${minutes}`;
  } else {
    return `${date.getMonth() + 1}月${date.getDate()}日 ${hours}:${minutes}`;
  }
};

export const generateId = () => Math.random().toString(36).substr(2, 9);

import React from 'react';
import { Check, Clock, Circle } from 'lucide-react';

interface TimelineItemProps {
  title: string;
  time: string;
  status: 'completed' | 'current' | 'future';
  isLast?: boolean;
  icon?: React.ReactNode;
}

export const TimelineItem: React.FC<TimelineItemProps> = ({ title, time, status, isLast, icon }) => {
  let circleColor = 'bg-gray-200 border-gray-200';
  let lineColor = 'border-gray-200';
  let textColor = 'text-gray-500';

  if (status === 'completed') {
    circleColor = 'bg-blue-500 border-blue-500';
    lineColor = 'border-blue-500';
    textColor = 'text-gray-900';
  } else if (status === 'current') {
    circleColor = 'bg-white border-blue-500 border-4';
    lineColor = 'border-gray-200';
    textColor = 'text-blue-600 font-semibold';
  }

  return (
    <div className="relative pl-8 pb-8 last:pb-0">
      {/* Vertical Line */}
      {!isLast && (
        <div 
          className={`absolute left-[11px] top-3 bottom-0 w-0.5 border-l-2 ${status === 'completed' ? 'border-blue-500' : 'border-gray-200'}`} 
        />
      )}

      {/* Circle Icon */}
      <div className={`absolute left-0 top-1 w-6 h-6 rounded-full flex items-center justify-center z-10 ${circleColor}`}>
        {status === 'completed' ? (
           <Check size={14} className="text-white" />
        ) : status === 'current' ? (
           <div className="w-2 h-2 bg-blue-500 rounded-full" />
        ) : (
           <div className="w-2 h-2 bg-gray-400 rounded-full" />
        )}
      </div>

      {/* Content */}
      <div className="flex flex-col">
        <span className={`text-sm ${textColor}`}>{title}</span>
        {time && <span className="text-xs text-gray-400 mt-1">{time}</span>}
      </div>
    </div>
  );
};

import React from 'react';
import { ChevronRight, ShieldAlert, CheckCircle2, Clock } from 'lucide-react';
import { Report, ReportStatus } from '../types';

interface ReportCardProps {
  report: Report;
  onClick: () => void;
  variant: 'received' | 'resolved'; // Determine which stage to show
}

export const ReportCard: React.FC<ReportCardProps> = ({ report, onClick, variant }) => {

  const isResolved = variant === 'resolved';

  // Dynamic Content based on variant
  const title = isResolved 
    ? "举报处理完成" 
    : "举报已受理";

  const Icon = isResolved ? CheckCircle2 : ShieldAlert;
  const iconColor = isResolved ? "text-green-500" : "text-blue-500";

  const bodyText = isResolved
    ? `关于您举报用户 ${report.targetUser.name} 的处理结果已更新。`
    : `我们已收到您对用户 ${report.targetUser.name} 的举报。`;

  const statusLabel = isResolved
    ? (report.status === ReportStatus.RESOLVED_PUNISHED ? "最终结论：✅ 举报成立，已处罚" : "最终结论：ℹ️ 暂未处罚")
    : "目前状态：排队等待核查中...";

  const actionText = isResolved ? "查看处理详情" : "查看实时进度";

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden max-w-sm w-full mx-auto my-4 animate-fade-in-up">
      {/* Header */}
      <div className="px-4 py-3 border-b border-gray-50 flex items-center gap-2">
        <Icon size={20} className={iconColor} />
        <span className="font-bold text-gray-800">{title}</span>
      </div>

      {/* Body */}
      <div className="px-4 py-3">
        <p className="text-gray-600 text-sm mb-3 leading-relaxed">
          {bodyText}
        </p>

        {!isResolved && (
           <div className="text-sm text-gray-500 mb-3">
             <span className="block">举报类型：{report.type}</span>
           </div>
        )}

        <div className={`text-sm ${isResolved && report.status === ReportStatus.RESOLVED_PUNISHED ? 'text-green-600 font-medium' : 'text-gray-500'}`}>
          {statusLabel}
        </div>
      </div>

      {/* Footer / Action */}
      <div 
        onClick={onClick}
        className="px-4 py-3 bg-gray-50 flex items-center justify-between cursor-pointer hover:bg-gray-100 transition-colors"
      >
        <span className="text-sm text-blue-500 font-medium">{actionText}</span>
        <ChevronRight size={16} className="text-gray-400" />
      </div>
    </div>
  );
};

